const customerMessage =
  body.content ||
  msg.content ||
  '';

const channel =
  inbox.name ||
  conversation.channel ||
  'Chatwoot';

const userId =
  (sender.id ?? sender.identifier ?? conversation.contact_inbox?.contact_id ?? null);

const existingOrderId =
