function fillFromSamRecapLines(allLines, gaps) {
  const out = { femaleSexQty: 0, maleSexQty: 0 };
  const needAny =
    gaps.needQty || gaps.needCat || gaps.needWt || gaps.needTime || gaps.needLoc;
