        content.match(/\border\s+is\s+for\s+(\d+)\b/i) ||
        content.match(/\byour\s+order\s+is\s+for\s+(\d+)\b/i) ||
        content.match(/\bfor\s+(\d+)\s+(?:female|male)\s+(?:pig|pigs)/i) ||
