const item = $input.first().json;
const os = item.order_state || {};
const slim = {};

if (os.customer_name) slim.customer_name = os.customer_name;
if (os.customer_language) slim.customer_language = os.customer_language;
if (os.existing_order_id) slim.existing_order_id = os.existing_order_id;
if (os.existing_order_status) slim.existing_order_status = os.existing_order_status;
if (os.conversation_mode) slim.conversation_mode = os.conversation_mode;
if (os.pending_action) slim.pending_action = os.pending_action;

const validPm = ['Cash', 'EFT'];
const pm = validPm.includes(os.detected_payment_method) ? os.detected_payment_method
         : validPm.includes(os.payment_method) ? os.payment_method
         : null;
if (pm) slim.payment_method = pm;

if (os.requested_quantity != null) slim.requested_quantity = os.requested_quantity;
if (os.requested_category) slim.requested_category = os.requested_category;
if (os.requested_weight_range) slim.requested_weight_range = os.requested_weight_range;
if (os.requested_sex) slim.requested_sex = os.requested_sex;
if (os.timing_preference) slim.timing_preference = os.timing_preference;
if (os.collection_location) slim.collection_location = os.collection_location;

const intents = ['quote_intent', 'order_commitment_intent', 'conversation_commitment_intent', 'cancel_order_intent', 'send_for_approval_intent', 'has_existing_draft'];
for (const key of intents) {
  if (os[key] !== undefined) slim[key] = os[key];
}

if (Array.isArray(os.requested_items) && os.requested_items.length > 0) {
  slim.requested_items_compact = os.requested_items.slice(0, 5).map(function(i) {
    return { qty: i.quantity, sex: i.sex, category: i.category, weight_range: i.weight_range };
  });
}

function toNum(value) {
  const n = Number(value);
  return Number.isNaN(n) ? 0 : n;
}

function isIncompleteSyncRow(r) {
  if (!r) return false;
  const status = r.match_status || '';
  const requested = toNum(r.requested_quantity);
  const matched = toNum(r.matched_quantity);
  return ['partial_match', 'no_match', 'error'].includes(status) || matched < requested;
}

const sc = {};
if (item.success !== undefined) {
  sc.success = item.success;
  if (item.message) sc.message = String(item.message).slice(0, 200);
}
if (item.backend_success !== undefined) sc.backend_success = item.backend_success;
if (item.backend_error) sc.backend_error = String(item.backend_error).slice(0, 200);
if (item.complete_fulfillment !== undefined) sc.complete_fulfillment = item.complete_fulfillment;
if (item.fulfillment_status) sc.fulfillment_status = item.fulfillment_status;
if (item.requested_total != null) sc.requested_total = item.requested_total;
if (item.matched_total != null) sc.matched_total = item.matched_total;
if (item.unmatched_total != null) sc.unmatched_total = item.unmatched_total;

const syncRes = Array.isArray(item.results) && item.results.length
  ? item.results
  : (Array.isArray(item.sync_results) && item.sync_results.length ? item.sync_results : []);

if (item.partial_fulfillment === true) sc.partial_fulfillment = true;

if (syncRes.length > 0) {
  sc.had_errors = syncRes.some(function(r) { return r.error && r.error !== ''; });
  sc.had_partial = syncRes.some(function(r) { return r.match_status === 'partial_match'; });
  sc.had_no_match = syncRes.some(function(r) { return r.match_status === 'no_match'; });
  sc.had_incomplete = syncRes.some(isIncompleteSyncRow);
  if (sc.had_partial || sc.had_no_match || sc.had_incomplete) sc.partial_fulfillment = true;
  if (sc.had_incomplete && sc.complete_fulfillment === undefined) sc.complete_fulfillment = false;

  const raw = syncRes.map(function(r) { return (r.request_item_key || '?') + ': ' + (r.match_status || '?'); }).join(', ');
  sc.summary = raw.length > 300 ? raw.slice(0, 297) + '...' : raw;

  const partialBits = [];
  for (let i = 0; i < syncRes.length; i++) {
    const r = syncRes[i];
    if (!isIncompleteSyncRow(r)) continue;
    const key = r.request_item_key || ('item_' + (i + 1));
    const status = r.match_status || 'unknown';
    const req = r.requested_quantity;
    const lined = r.matched_quantity;
    const avail = r.available_quantity;
    let altStr = '';
    if (Array.isArray(r.alternatives) && r.alternatives.length > 0) {
      altStr = r.alternatives.slice(0, 4).map(function(a) {
        const band = a.weight_band || a.sale_category || '?';
        const n = a.available_count != null ? a.available_count : '';
        return n !== '' ? (band + ' x' + n) : band;
      }).join('; ');
    }
    let chunk = key + ': status=' + status + ', requested=' + req + ', added_to_draft=' + lined;
    if (avail != null && avail !== '') chunk += ', matched_in_requested_band=' + avail;
    if (altStr) chunk += '; other_bands_same_category=' + altStr;
    partialBits.push(chunk);
  }
  if (partialBits.length > 0) {
    sc.partial_stock_detail = partialBits.join(' | ').slice(0, 550);
  }
}

if (item.active_order_lookup_status) {
  sc.active_order_lookup_status = item.active_order_lookup_status;
  sc.active_order_match_count = item.active_order_match_count || 0;
  if (item.active_order_lookup_message) {
    sc.active_order_lookup_message = String(item.active_order_lookup_message).slice(0, 200);
  }
}

if (item.active_order_context && item.active_order_context.order) {
  const ao = item.active_order_context.order;
  sc.active_order_summary = [
    ao.order_id,
    ao.order_status,
    ao.approval_status,
    ao.requested_quantity ? ('qty ' + ao.requested_quantity) : '',
    ao.requested_category,
    ao.requested_weight_range,
    ao.requested_sex,
    ao.collection_location,
    ao.payment_method ? ('payment ' + ao.payment_method) : '',
    ao.active_line_count != null ? ('active lines ' + ao.active_line_count) : '',
    ao.active_line_total != null ? ('active total ' + ao.active_line_total) : ''
  ].filter(Boolean).join(' | ').slice(0, 400);

  if (Array.isArray(item.active_order_context.line_groups) && item.active_order_context.line_groups.length > 0) {
    sc.active_order_line_groups = item.active_order_context.line_groups.slice(0, 5).map(function(g) {
      return [g.quantity + 'x', g.sex, g.sale_category, g.weight_band, g.line_status, g.reserved_status, g.unit_price ? ('R' + g.unit_price) : ''].filter(Boolean).join(' ');
    }).join('; ').slice(0, 400);
  }
}

if (Array.isArray(item.active_order_matches) && item.active_order_matches.length > 0) {
  sc.active_order_matches = item.active_order_matches.slice(0, 5).map(function(m) {
    return [
      m.order_id,
      m.order_status,
      m.requested_quantity ? ('qty ' + m.requested_quantity) : '',
      m.requested_category,
      m.requested_weight_range,
      m.active_line_count != null ? ('active lines ' + m.active_line_count) : ''
    ].filter(Boolean).join(' | ');
  }).join(' || ').slice(0, 500);
}

const out = Object.assign({}, item, { sam_order_state_slim: slim });
if (Object.keys(sc).length > 0) out.sam_steward_result_compact = sc;

return [{ json: out }];

