const customerPhone = conversationId
  ? ''
  : clean(inputs.customer_phone || main.customer_phone || main.CustomerPhone);

return [{
  json: {
    action: 'get_active_customer_order_context',
    conversation_id: conversationId,
    customer_phone: customerPhone,
    changed_by: 'Sam'
  }
}];

const main = $('Code - Skip Order Context Fetch').first().json;
const r = $json || {};
const lookupStatus = String(r.lookup_status || '').trim();
const activeCtx = r.active_order_context && typeof r.active_order_context === 'object'
  ? r.active_order_context
  : null;
const activeOrder = activeCtx && activeCtx.order ? activeCtx.order : null;
const singleMatch = r.active_order_context_fetch_ok === true && lookupStatus === 'single_match' && Boolean(activeOrder);

let existingCtx = null;
if (singleMatch) {
  existingCtx = {
    order: {
      order_id: activeOrder.order_id || '',
      order_status: activeOrder.order_status || '',
      approval_status: activeOrder.approval_status || '',
      payment_status: activeOrder.payment_status || '',
      requested_category: activeOrder.requested_category || '',
      requested_weight_range: activeOrder.requested_weight_range || '',
      requested_sex: activeOrder.requested_sex || '',
      requested_quantity: activeOrder.requested_quantity,
      collection_location: activeOrder.collection_location || '',
      line_count: activeOrder.active_line_count,
      active_line_count: activeOrder.active_line_count,
      line_count_includes_cancelled: true,
      payment_method: activeOrder.payment_method || ''
    },
    lines: []
  };
}

const orderId = singleMatch ? String(activeOrder.order_id || '').trim() : '';
const orderStatus = singleMatch ? String(activeOrder.order_status || '').trim() : '';

return [{
  json: {
    ...main,
    existing_order_id: orderId || main.existing_order_id || '',
    ExistingOrderId: orderId || main.ExistingOrderId || '',
    existing_order_status: orderStatus || main.existing_order_status || '',
    ExistingOrderStatus: orderStatus || main.ExistingOrderStatus || '',
    existing_order_context: existingCtx,
    order_context_fetch_ok: singleMatch || lookupStatus !== 'single_match',
    active_order_context_fetch_ok: r.active_order_context_fetch_ok === true,
    active_order_lookup_status: lookupStatus || 'error',
    active_order_match_count: Number(r.match_count || 0),
    active_order_context: activeCtx,
    active_order_matches: Array.isArray(r.active_order_matches) ? r.active_order_matches : [],
    active_order_lookup_message: String(r.message || '').slice(0, 500)
  }
}];
